from elasticsearch import Elasticsearch
from flask import Flask, request, jsonify
import re

app = Flask(__name__)

# Initialize Elasticsearch client
es = Elasticsearch(['localhost:9200'])

# Whitelist of allowed aggregation types and field names
ALLOWED_AGG_TYPES = {
    'sum', 'avg', 'min', 'max', 'cardinality', 'value_count',
    'stats', 'extended_stats', 'percentiles', 'terms', 'date_histogram'
}

ALLOWED_FIELDS = {
    'price', 'quantity', 'total', 'timestamp', 'category', 
    'user_id', 'product_id', 'status', 'amount', 'count'
}

# Predefined safe script templates
SAFE_SCRIPT_TEMPLATES = {
    'price_with_tax': {
        'source': "doc['price'].value * (1 + params.tax_rate)",
        'params': {'tax_rate': 0.0}
    },
    'total_calculation': {
        'source': "doc['price'].value * doc['quantity'].value",
        'params': {}
    },
    'discount_price': {
        'source': "doc['price'].value * (1 - params.discount)",
        'params': {'discount': 0.0}
    },
    'percentage_change': {
        'source': "((doc['current'].value - doc['previous'].value) / doc['previous'].value) * 100",
        'params': {}
    }
}


def validate_field_name(field_name):
    """Validate that field name is in whitelist"""
    if not isinstance(field_name, str):
        return False
    return field_name in ALLOWED_FIELDS


def validate_params(params):
    """Validate script parameters to ensure they are safe"""
    if not isinstance(params, dict):
        return False
    
    for key, value in params.items():
        # Only allow alphanumeric keys
        if not re.match(r'^[a-zA-Z_][a-zA-Z0-9_]*$', key):
            return False
        # Only allow numeric or boolean values
        if not isinstance(value, (int, float, bool)):
            return False
        # Prevent extreme values
        if isinstance(value, (int, float)) and (abs(value) > 1e10):
            return False
    
    return True


def build_safe_aggregation(agg_config):
    """Build aggregation query using whitelisted components only"""
    if not isinstance(agg_config, dict):
        raise ValueError("Invalid aggregation configuration")
    
    agg_type = agg_config.get('type')
    if agg_type not in ALLOWED_AGG_TYPES:
        raise ValueError(f"Aggregation type '{agg_type}' not allowed")
    
    field = agg_config.get('field')
    if field and not validate_field_name(field):
        raise ValueError(f"Field '{field}' not allowed")
    
    # Build aggregation based on type
    agg_body = {}
    
    if agg_type in ['sum', 'avg', 'min', 'max', 'cardinality', 'value_count']:
        if not field:
            raise ValueError(f"Field required for {agg_type} aggregation")
        agg_body[agg_type] = {'field': field}
    
    elif agg_type in ['stats', 'extended_stats', 'percentiles']:
        if not field:
            raise ValueError(f"Field required for {agg_type} aggregation")
        agg_body[agg_type] = {'field': field}
    
    elif agg_type == 'terms':
        if not field:
            raise ValueError("Field required for terms aggregation")
        agg_body['terms'] = {
            'field': field,
            'size': min(agg_config.get('size', 10), 1000)  # Cap at 1000
        }
    
    elif agg_type == 'date_histogram':
        if not field:
            raise ValueError("Field required for date_histogram aggregation")
        interval = agg_config.get('interval', '1d')
        # Whitelist intervals
        if interval not in ['1m', '5m', '15m', '30m', '1h', '6h', '12h', '1d', '7d', '30d']:
            raise ValueError(f"Interval '{interval}' not allowed")
        agg_body['date_histogram'] = {
            'field': field,
            'interval': interval
        }
    
    return agg_body


def build_safe_scripted_aggregation(script_config):
    """Build aggregation with predefined safe script templates"""
    if not isinstance(script_config, dict):
        raise ValueError("Invalid script configuration")
    
    template_name = script_config.get('template')
    if template_name not in SAFE_SCRIPT_TEMPLATES:
        raise ValueError(f"Script template '{template_name}' not found")
    
    template = SAFE_SCRIPT_TEMPLATES[template_name].copy()
    user_params = script_config.get('params', {})
    
    # Validate user-provided parameters
    if not validate_params(user_params):
        raise ValueError("Invalid script parameters")
    
    # Merge with template params (user params override defaults)
    template['params'].update(user_params)
    
    # Build scripted metric aggregation
    agg_body = {
        'sum': {
            'script': {
                'source': template['source'],
                'lang': 'painless',
                'params': template['params']
            }
        }
    }
    
    return agg_body


@app.route('/api/analytics/aggregate', methods=['POST'])
def execute_aggregation():
    """Execute safe aggregation query"""
    try:
        data = request.get_json()
        
        if not data:
            return jsonify({'error': 'No data provided'}), 400
        
        index_name = data.get('index', 'analytics')
        # Validate index name
        if not re.match(r'^[a-z0-9_-]+$', index_name):
            return jsonify({'error': 'Invalid index name'}), 400
        
        query_body = {
            'size': 0,
            'aggs': {}
        }
        
        # Handle standard aggregations
        if 'aggregations' in data:
            for agg_name, agg_config in data['aggregations'].items():
                # Validate aggregation name
                if not re.match(r'^[a-zA-Z_][a-zA-Z0-9_]*$', agg_name):
                    return jsonify({'error': f'Invalid aggregation name: {agg_name}'}), 400
                
                query_body['aggs'][agg_name] = build_safe_aggregation(agg_config)
        
        # Handle scripted aggregations with templates
        if 'scripted_aggregations' in data:
            for agg_name, script_config in data['scripted_aggregations'].items():
                # Validate aggregation name
                if not re.match(r'^[a-zA-Z_][a-zA-Z0-9_]*$', agg_name):
                    return jsonify({'error': f'Invalid aggregation name: {agg_name}'}), 400
                
                query_body['aggs'][agg_name] = build_safe_scripted_aggregation(script_config)
        
        # Add optional query filter
        if 'query' in data:
            # Only allow simple term queries for safety
            query_filter = data['query']
            if 'term' in query_filter:
                term_field = list(query_filter['term'].keys())[0]
                if validate_field_name(term_field):
                    query_body['query'] = query_filter
        
        # Execute query
        result = es.search(index=index_name, body=query_body)
        
        return jsonify({
            'success': True,
            'aggregations': result.get('aggregations', {}),
            'took': result.get('took', 0)
        })
    
    except ValueError as e:
        return jsonify({'error': str(e)}), 400
    except Exception as e:
        return jsonify({'error': 'Internal server error'}), 500


@app.route('/api/analytics/templates', methods=['GET'])
def list_templates():
    """List available safe script templates"""
    templates = {}
    for name, template in SAFE_SCRIPT_TEMPLATES.items():
        templates[name] = {
            'description': template['source'],
            'required_params': list(template['params'].keys())
        }
    return jsonify({'templates': templates})


